import{_ as r,c as o,o as i,a5 as t,j as e}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"v1.1.8: Major Desktop Performance Boost","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.8.md","filePath":"en/changelog/v1.1.8.md","lastUpdated":1772014034000}'),n={name:"en/changelog/v1.1.8.md"};function s(l,a,d,c,p,h){return i(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="v1-1-8-major-desktop-performance-boost" tabindex="-1">v1.1.8: Major Desktop Performance Boost <a class="header-anchor" href="#v1-1-8-major-desktop-performance-boost" aria-label="Permalink to “v1.1.8: Major Desktop Performance Boost”">​</a></h1><p><strong>Release Date</strong>: January 9, 2026</p><hr><h2 id="one-line-summary" tabindex="-1">One-Line Summary <a class="header-anchor" href="#one-line-summary" aria-label="Permalink to “One-Line Summary”">​</a></h2><p>This update focuses on <strong>desktop performance optimization</strong>, long conversations no longer lag, plus new multi-select Q&amp;A feature.</p><hr><h2 id="new-feature-multi-select-q-a" tabindex="-1">New Feature: Multi-Select Q&amp;A <a class="header-anchor" href="#new-feature-multi-select-q-a" aria-label="Permalink to “New Feature: Multi-Select Q&amp;A”">​</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>OpenCode now supports <strong>multi-select type Q&amp;A</strong>. When AI needs you to make choices, you can select multiple options at once.</p><h3 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to “Use Cases”">​</a></h3><p>For example, when AI asks &quot;Which files need to be updated for this refactor?&quot;, you can select multiple files at once instead of one by one.</p><hr><h2 id="desktop-app-major-performance-boost" tabindex="-1">Desktop App: Major Performance Boost <a class="header-anchor" href="#desktop-app-major-performance-boost" aria-label="Permalink to “Desktop App: Major Performance Boost”">​</a></h2><p>This desktop version has extensive performance optimizations, especially for <strong>long conversation scenarios</strong>:</p><table tabindex="0"><thead><tr><th>Optimization</th><th>Effect</th></tr></thead><tbody><tr><td>Markdown cache</td><td>No longer re-renders already displayed content</td></tr><tr><td>Lazy load Diff</td><td>Code differences loaded on demand, no lag</td></tr><tr><td>Chunked message loading</td><td>Smoother scrolling in long conversations</td></tr><tr><td>Preload adjacent sessions</td><td>Faster session switching</td></tr></tbody></table><p><strong>In short</strong>: Long conversations no longer lag.</p><hr><h2 id="improvement-more-precise-file-autocomplete" tabindex="-1">Improvement: More Precise File Autocomplete <a class="header-anchor" href="#improvement-more-precise-file-autocomplete" aria-label="Permalink to “Improvement: More Precise File Autocomplete”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>When using <code>@</code> to reference files in the input box, autocomplete only matched filenames, sometimes making it hard to find the files you want.</p><h3 id="current-behavior" tabindex="-1">Current Behavior <a class="header-anchor" href="#current-behavior" aria-label="Permalink to “Current Behavior”">​</a></h3><p>Now uses <strong>full file path</strong> for fuzzy matching, making it easier to find target files.</p><p>For example, typing <code>@comp/but</code> can match <code>src/components/Button.tsx</code>.</p><hr><h2 id="improvement-escape-key-no-longer-accidentally-triggers" tabindex="-1">Improvement: Escape Key No Longer Accidentally Triggers <a class="header-anchor" href="#improvement-escape-key-no-longer-accidentally-triggers" aria-label="Permalink to “Improvement: Escape Key No Longer Accidentally Triggers”">​</a></h2><h3 id="previous-issue-1" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-1" aria-label="Permalink to “Previous Issue”">​</a></h3><p>When pressing Escape to close a popup (dialog), the key event would &quot;pass through&quot; to the main interface, potentially triggering other actions.</p><h3 id="current-behavior-1" tabindex="-1">Current Behavior <a class="header-anchor" href="#current-behavior-1" aria-label="Permalink to “Current Behavior”">​</a></h3><p>Escape key events are now correctly intercepted by popups, won&#39;t affect main interface.</p><hr><h2 id="desktop-app-project-sidebar-fix" tabindex="-1">Desktop App: Project Sidebar Fix <a class="header-anchor" href="#desktop-app-project-sidebar-fix" aria-label="Permalink to “Desktop App: Project Sidebar Fix”">​</a></h2><h3 id="previous-issue-2" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-2" aria-label="Permalink to “Previous Issue”">​</a></h3><p>Project sidebar sometimes only showed folder names, not complete project names.</p><h3 id="current-behavior-2" tabindex="-1">Current Behavior <a class="header-anchor" href="#current-behavior-2" aria-label="Permalink to “Current Behavior”">​</a></h3><p>Now correctly displays project names.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Using desktop app</td><td>✅ Strongly recommended</td></tr><tr><td>Long conversations often lag</td><td>✅ Upgrade</td></tr><tr><td>Everything works fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',39),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full changelog</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Upgrade OpenTUI to v0.1.70</li><li>Support multi-select Q&amp;A</li><li>Add cargofmt documentation (@marc2332)</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Prevent Escape key from passing through from popup to main interface</li><li>File autocomplete uses full path for fuzzy matching (@bagatka)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Revert external links opening in default browser fix</li><li>Cache session-level store, add optional context gating</li><li>Incremental message rendering, Markdown cache, lazy load Diff</li><li>Control hydration side effects and store loading timing</li><li>Preload adjacent sessions</li><li>Implement chunked message loading and lazy load Diff for performance</li><li>Fix project sidebar folder name display issue (@0xajka)</li></ul><h3 id="community-contributors" tabindex="-1">Community Contributors <a class="header-anchor" href="#community-contributors" aria-label="Permalink to “Community Contributors”">​</a></h3><ul><li>@marc2332: Add cargofmt documentation</li><li>@bagatka: File autocomplete optimization</li><li>@0xajka: Project sidebar fix</li><li>@Anthuang: Add Vesper theme</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const f=r(n,[["render",s]]);export{u as __pageData,f as default};
